import{_ as a,o as t,c as b,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"光剑","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/光剑.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/光剑.md"}'),s={name:"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/光剑.md"};function o(d,e,l,i,_,c){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"光剑",tabindex:"-1"},[p("光剑 "),r("a",{class:"header-anchor",href:"#光剑","aria-label":'Permalink to "光剑"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘003B")])])],-1),n('<h1 id="光剑-1" tabindex="-1">光剑 <a class="header-anchor" href="#光剑-1" aria-label="Permalink to &quot;光剑&quot;">​</a></h1><p>不同级别的光剑可进行差价升级。</p><p>本质：科技本质</p><p>见习用光剑<br> D+500<br> 专门为绝地幼童所制造的初学用光剑，所用材质并非凯伯水晶，令见习者能更快上手。购买者可自定义光剑的颜色。<br> 武器伤害：5L<br> 体积：1（剑刃升起后为3）<br> 专业：光剑<br> 类型：光剑<br> 使用该武器需要消耗价值100分的能量电池，一枚电池可开启光剑10轮。<br> 将光剑升起所需动作与从触手可及之处拿取武器是同等动作。</p><p>特性：破甲8<br> 以本武器攻击时，若对方具有格挡防御、且使用的格挡武器不具有【能量武器】特性，则你可将计算防御后本武器剩余的破甲值用于减少对方的格挡防御。</p><p>光剑<br> C+1000<br> 对于绝地武士而言，光剑与他们的性命同等重要。合格的光剑通常由绝地武士亲自制造，他们会寻找合适的凯伯水晶作为承载自身原力的基石。一名绝地武士通常会花费几周的时间制作光剑。<br> 光剑分为三部分，第一部分为能源部分，采用迪亚特素电池，为光剑的电磁体约束装置提供能源。第二部分为惰性绝缘体环绕的涡流环，其确保了光剑的能量充分聚焦于核心组件—凯伯水晶上。第三部分为光剑的水晶仓室，能源经过凯伯水晶转换聚焦，接着通过循环场能发射器将能量从基座部分升起并形成光剑。<br> 一柄光剑的剑刃颜色与绝地武士的原力性质息息相关，若武士为人正直，则光剑通常是蓝色或者绿色；若武士对原力的信念有所动摇，则光剑可能变为粉色或者紫色：若武士彻底背弃光明，投身黑暗，则光剑颜色会变为红色。<br> 武器伤害：10L<br> 武器体积：1（剑刃升起后为3）<br> 专业：剑<br> 武器类型：光剑<br> 使用该武器需要消耗价值500分的能量电池，一枚电池可供使用20轮。若你具有原力，可消耗3点原力以维持光剑的开启10轮。<br> 将光剑升起所需动作与从触手可及之处拿取武器是同等动作。</p><p>特性：破甲10 能量武器<br> 以本武器攻击时，若对方具有格挡防御、且使用的格挡武器不具有【能量武器】特性，则你可将计算防御后剩余的破甲值用于减少对方的格挡防御。<br> 增幅：花招动作消耗3点原力，本武器的破甲值提升5点，持续一轮。</p><p>大师级光剑<br> B+2000<br> 只有最出色的绝地武士可以驾驭的光剑，与一般的光剑不同，大师级光剑所用的凯伯水晶更多，制造光剑的技艺更为精湛， 光剑对于原力的亲和性也更强。<br> 武器伤害：18L<br> 武器体积：1（剑刃升起后为3）<br> 专业：剑<br> 武器类型：光剑<br> 使用该武器需要原力以维持光剑的开启，每3点能量可开启10轮。<br> 将光剑升起所需动作与从触手可及之处拿取武器是同等动作。</p><p>特性：破甲15 能量武器<br> 以本武器攻击时，你可将计算防御后剩余的破甲值用于减少对方的格挡防御或转为攻击上的光能加值，至多转化等同此武器提供的破甲值的光能加值。<br> 增幅：花招动作消耗5点原力，令本武器的破甲值提升任一原力关键属性点，持续一轮。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',11)])])}const m=a(s,[["render",o]]);export{f as __pageData,m as default};
